class Solution:
    def maxScore(self, grid):
        # Independent brute force: recursively decide, row by row, whether to
        # skip it or claim one of its distinct values, tracking used values.
        m = len(grid)
        best = [0]

        def dfs(row, used_values, score):
            if row == m:
                best[0] = max(best[0], score)
                return
            dfs(row + 1, used_values, score)
            for v in set(grid[row]):
                if v not in used_values:
                    used_values.add(v)
                    dfs(row + 1, used_values, score + v)
                    used_values.remove(v)

        dfs(0, set(), 0)
        return best[0]

