from collections import defaultdict

class Solution:
    def maxScore(self, grid):
        value_rows = defaultdict(set)
        for r, row in enumerate(grid):
            for v in row:
                value_rows[v].add(r)
        match_row = {}

        def try_kuhn(v, visited):
            for r in value_rows[v]:
                if r in visited:
                    continue
                visited.add(r)
                if r not in match_row or try_kuhn(match_row[r], visited):
                    match_row[r] = v
                    return True
            return False

        total = 0
        for v in sorted(value_rows.keys(), reverse=True):
            if try_kuhn(v, set()):
                total += v
        return total

