var maxScore = function(grid) {
    const valueRows = new Map();
    for (let r = 0; r < grid.length; r++) {
        for (const v of grid[r]) {
            if (!valueRows.has(v)) valueRows.set(v, new Set());
            valueRows.get(v).add(r);
        }
    }
    const matchRow = new Map();
    function tryKuhn(v, visited) {
        for (const r of valueRows.get(v)) {
            if (visited.has(r)) continue;
            visited.add(r);
            if (!matchRow.has(r) || tryKuhn(matchRow.get(r), visited)) {
                matchRow.set(r, v);
                return true;
            }
        }
        return false;
    }
    const values = Array.from(valueRows.keys()).sort((a, b) => b - a);
    let total = 0;
    for (const v of values) {
        if (tryKuhn(v, new Set())) total += v;
    }
    return total;
};
